package com.example.mpos.order;
import android.content.Intent;import android.database.Cursor;import android.os.Bundle;import android.widget.*;import androidx.appcompat.app.AppCompatActivity;import com.example.mpos.R;import com.example.mpos.database.DatabaseHelper;import com.example.mpos.ui.BottomNavHelper;import com.example.mpos.utils.CurrencyUtils;import java.util.*;
public class OrderListActivity extends AppCompatActivity{List<Long> ids=new ArrayList<>();ArrayAdapter<String>a;DatabaseHelper db;public void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_order_list);BottomNavHelper.bind(this);db=new DatabaseHelper(this);a=new ArrayAdapter<>(this,android.R.layout.simple_list_item_1,new ArrayList<>());ListView l=findViewById(R.id.listOrders);l.setAdapter(a);l.setOnItemClickListener((p,v,x,id)->{if(x>=ids.size())return;Intent i=new Intent(this,OrderDetailActivity.class);i.putExtra("order_id",ids.get(x));startActivity(i);});load();}protected void onResume(){super.onResume();if(db!=null)load();}void load(){Cursor c=db.getReadableDatabase().rawQuery("SELECT id,order_code,status,total_amount,created_at FROM orders ORDER BY created_at DESC",null);List<String> rows=new ArrayList<>();ids.clear();try{while(c.moveToNext()){ids.add(c.getLong(0));rows.add(c.getString(1)+" • "+c.getString(2)+"\n"+CurrencyUtils.vnd(c.getLong(3)));}}finally{c.close();}if(rows.isEmpty())rows.add("Chưa có đơn hàng\nTạo đơn mới từ màn Bán hàng");a.clear();a.addAll(rows);a.notifyDataSetChanged();}}
